module Bar(output [7:0] b); endmodule
module Foo(input clock, input reset, output [7:0] b);
  reg [7:0] r;
  Bar bar();
  always @(posedge clock) if (reset) r <= 8'h4; else r <= 8'h0;
  assign b = r;
endmodule

module Bar(output [7:0] b); endmodule
module Foo(output [7:0] b);
  Bar bar();
  assign b = 8'h0;
endmodule

reg [7:0] r1, r2;
always @(posedge clock) begin
  if (reset) r1 <= 8'h4;
  else r1 <= 8'h0;
  r2 <= r1;
end
